    let n = n as usize;
    let edges: Vec<Vec<usize>> = edges.into_iter().map(|e| e.into_iter().map(|x| x as usize).collect()).collect();

    // Sort edges by weight
    edges.sort_by(|a, b| a[2].cmp(&b[2]));

    // Build adjacency list
    let mut adj: Vec<Vec<(usize, usize)>> = vec![vec![]; n];
    for e in &edges {
        let u = e[0];
        let v = e[1];
        let w = e[2];
        adj[u].push((v, w));
        adj[v].push((u, w));
    }

    // Union-Find data structure
    struct UnionFind {
        parent: Vec<usize>,
        rank: Vec<usize>,
    }

    impl UnionFind {
        fn new(size: usize) -> Self {
            let parent: Vec<usize> = (0..size).collect();
            let rank: Vec<usize> = vec![0; size];
            UnionFind { parent, rank }
        }

        fn find(&mut self, x: usize) -> usize {
            if self.parent[x] != x {
                self.parent[x] = self.find(self.parent[x]);
            }
            self.parent[x]
        }

        fn union(&mut self, x: usize, y: usize) -> bool {
            let x_root = self.find(x);
            let y_root = self.find(y);

            if x_root == y_root {
                return false;
            }

            if self.rank[x_root] < self.rank[y_root] {
                self.parent[x_root] = y_root;
            } else {
                self.parent[y_root] = x_root;
                if self.rank[x_root] == self.rank[y_root] {
                    self.rank[x_root] += 1;
                }
            }
            true
        }
    }

    let mut uf = UnionFind::new(n);
    let mut max_edge_in_component: Vec<usize> = vec![0; n];

    let mut result = 0;
    let mut components = n;

    for e in &edges {
