            max_edge_in_component[root_v] = std::cmp::max(max_edge_in_component[root_v], w);

            let new_max = std::cmp::max(max_edge_in_component[root_u], max_edge_in_component[root_v]);
            max_edge_in_component[root_u] = new_max;

            components -= 1;

            if components == k {
                return new_max as i64;
            }
        }
    }

    *max_edge_in_component.iter().max().unwrap() as i64
}
