```typescript
function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by weight
    edges.sort((a, b) => a[2] - b[2]);

    // Build adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);

    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }

    // Union-Find data structure
    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(size: number) {
            this.parent = Array.from({ length: size }, (_, i) => i);
            this.rank = Array(size).fill(0);
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false;
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize Union-Find
    const uf = new UnionFind(n);

    // Keep track of the maximum edge weight in each component
    const maxEdgeInComponent: number[] = Array(n).fill(0);

    // Process edges in increasing order of weight
    let result = 0;
    let components = n;

    for (const [u, v, w] of edges) {
        const rootU = uf.find(u);
        const rootV = uf.find(v);

        if (rootU !== rootV) {
            // Merge the components
            uf.union(rootU, rootV);

            // Update the maximum edge weight in the new component
            maxEdgeInComponent[rootU] = Math.max(maxEdgeInComponent[rootU], w);
            maxEdgeInComponent[rootV] = Math.max(maxEdgeInComponent[rootV], w);

            // The new component's max edge is the max of the two components
            const newMax = Math.max(maxEdgeInComponent[rootU], maxEdgeInComponent[rootV]);
            maxEdgeInComponent[rootU] = newMax;

            // Decrement component count
            components--;

            // If we have reached the desired number of components, return the max edge
            if (components === k) {
                return newMax;
            }
        }
    }

    // If we haven't returned yet, the answer is the maximum edge in the remaining component
    return Math.max(...maxEdgeInComponent);
}
